#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int *data;
    int size;
    int cap;
} Node;

void push(Node *v, int x) {
    if (v->size == v->cap) {
        v->cap = v->cap ? v->cap * 2 : 4;
        v->data = realloc(v->data, v->cap * sizeof(int));
    }
    v->data[v->size++] = x;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        // map value -> list of positions using hash table (simple chaining)
        // Since Ai ≤ 1e6 and total N ≤ 1e6, we can allocate an array of pointers.
        Node *vec = (Node*)calloc(1000001, sizeof(Node));
        for (int i = 0; i < N; ++i) {
            push(&vec[A[i]], i + 1); // positions are 1‑based
        }
        long long ans = 0;
        for (int v = 1; v <= 1000000; ++v) {
            Node *lst = &vec[v];
            int k = lst->size;
            if (k < v) continue;
            // sentinel positions: p0 = 0, p_{k+1} = N+1
            for (int i = 0; i + v - 1 < k; ++i) {
                int leftPrev = (i == 0) ? 0 : lst->data[i-1];
                int leftChoices = lst->data[i] - leftPrev;
                int rightNext = (i + v == k) ? N + 1 : lst->data[i+v];
                int rightChoices = rightNext - lst->data[i+v-1];
                ans += (long long)v * leftChoices * rightChoices;
            }
        }
        printf("%lld\n", ans);
        // free memory
        for (int v = 1; v <= 1000000; ++v) {
            if (vec[v].data) free(vec[v].data);
        }
        free(vec);
        free(A);
    }
    return 0;
}

