import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        final int MAXV = 1_000_000;
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextInt();
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] pos = new ArrayList[MAXV + 1];
            for (int i = 0; i < N; i++) {
                int v = A[i];
                if (pos[v] == null) pos[v] = new ArrayList<>();
                pos[v].add(i + 1); // 1‑based
            }
            long ans = 0L;
            for (int v = 1; v <= MAXV; v++) {
                ArrayList<Integer> list = pos[v];
                if (list == null) continue;
                int k = list.size();
                if (k < v) continue;
                for (int i = 0; i + v - 1 < k; i++) {
                    int leftPrev = (i == 0) ? 0 : list.get(i - 1);
                    long leftChoices = list.get(i) - leftPrev;
                    int rightNext = (i + v == k) ? N + 1 : list.get(i + v);
                    long rightChoices = rightNext - list.get(i + v - 1);
                    ans += (long) v * leftChoices * rightChoices;
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner based on BufferedInputStream
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

