  const N = input[idx++];
  const A = new Array(N);
  for (let i = 0; i < N; ++i) A[i] = input[idx++];
  // positions per value
  const pos = Array.from({length: MAXV + 1}, () => []);
  for (let i = 0; i < N; ++i) {
    pos[A[i]].push(i + 1); // 1‑based
  }
  let ans = 0n;
